    34→  const [totalPages, setTotalPages] = useState(1);
    35→  const [totalItems, setTotalItems] = useState(0);
    36→  const [pageSize, setPageSize] = useState(DEFAULT_PAGE_SIZE_OPTIONS[0]);
    37→  const [searchTerm, setSearchTerm] = useState("");
    38→  const debouncedSearchTerm = useDebouncedValue(searchTerm, 500);
