    46→  const handleViewSalon = useCallback(async (salon: Salon): Promise<void> => {
    47→    try {
    48→      await selectSalon(salon);
    49→      navigate("/salon/agenda");
    50→    } catch {
    51→      toast.error("Erro ao selecionar salão");
    52→    }
    53→  }, [selectSalon, navigate]);
    54→
    55→  const handleToggleStatus = useCallback(async (salon: Salon): Promise<void> => {
    56→    try {
    57→      setIsTogglingStatus(true);
    58→
    59→      const updatedSalon = salon.active
    60→        ? await salonService.deactivate(salon.id)
    61→        : await salonService.activate(salon.id);
    62→
    63→      setSalons((prev) =>
    64→        prev.map((s) =>
    65→          s.id === salon.id ? { ...s, active: updatedSalon.active } : s
    66→        )
    67→      );
    68→
    69→      toast.success(
    70→        `Salão ${updatedSalon.active ? "ativado" : "desativado"} com sucesso!`
    71→      );
    72→    } catch {
    73→      toast.error("Erro ao alterar status do salão");
    74→    } finally {
    75→      setIsTogglingStatus(false);
    76→    }
    77→  }, []);
    78→
    79→  const loadSalons = useCallback(async (
    80→    page: number = 1,
    81→    search?: string,
    82→    status?: string,
    83→    limit: number = pageSize
