    89→        page,
    90→        limit,
    91→        search: searchParam,
    92→        status: status && status !== "all" ? status : undefined,
    93→        sortBy: "name",
    94→        sortOrder: "asc",
    95→      });
    96→
    97→      setSalons(response.data);
    98→      setTotalPages(response.totalPages || Math.ceil(response.total / limit));
    99→      setTotalItems(response.total || response.data.length);
   100→    } catch {
