   107→
   108→  useEffect(() => {
   109→    loadSalons(currentPage, debouncedSearchTerm, statusFilter, pageSize);
   110→  }, [currentPage, debouncedSearchTerm, statusFilter, pageSize, loadSalons]);
   111→
   112→  useEffect(() => {
   113→    setCurrentPage(1);
   114→  }, [debouncedSearchTerm, statusFilter]);
   115→
   116→  const handlePageSizeChange = (size: number): void => {
