   177→        />
   178→        <div className="flex items-center justify-center h-64">
   179→          <LoadingSpinner size="md" />
   180→        </div>
   181→      </EasySalonLayout>
   182→    );
   183→  }
   184→
   185→  return (
   186→    <EasySalonLayout
   187→      sideNavItems={getAdminNavItems(user?.role || "Easy Salon")}
   188→      sideNavTitle="Easy Salon"
   189→      sideNavSubtitle="Área Easy Salon"
   190→    >
   191→      <PageHeader
   192→        title="Gestão de Salões"
   193→        subtitle="Gerencie todos os salões cadastrados na plataforma"
   194→        action={{
   195→          label: "Novo salão",
   196→          onClick: handleAddSalon,
   197→        }}
   198→      />
   199→
   200→      {/* Barra de Ferramentas Responsiva */}
   201→      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
   202→        <div className="flex flex-col sm:flex-row items-center gap-2 w-full md:w-auto">
   203→          <div className="relative w-full sm:max-w-sm">
   204→            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
   205→            <Input
   206→              type="text"
   207→              placeholder="Buscar por nome, telefone ou endereço..."
   208→              value={searchTerm}
   209→              onChange={(e) => setSearchTerm(e.target.value)}
   210→              className="pl-10"
   211→            />
   212→          </div>
   213→          <Select value={statusFilter} onValueChange={setStatusFilter}>
   214→            <SelectTrigger className="w-full sm:w-40">
   215→              <SelectValue placeholder="Status" />
   216→            </SelectTrigger>
   217→            <SelectContent>
   218→              <SelectItem value="all">Todos</SelectItem>
   219→              <SelectItem value="active">Ativos</SelectItem>
   220→              <SelectItem value="inactive">Inativos</SelectItem>
   221→            </SelectContent>
   222→          </Select>
   223→        </div>
   224→      </div>
   225→
   226→      <DataTable<Salon>
   227→        data={salons}
   228→        columns={columns}
   229→        actions={salonActions}
   230→        mobileView="cards"
   231→        mobileCardConfig={{
   232→          title: "name",
   233→          subtitle: "phone",
   234→          badge: "active",
   235→        }}
   236→      />
   237→
   238→      {/* Controles de Paginação Responsivos */}
   239→      <ResponsivePagination
   240→        currentPage={currentPage}
   241→        totalPages={totalPages}
   242→        totalItems={totalItems}
   243→        pageSize={pageSize}
   244→        onPageChange={setCurrentPage}
   245→        onPageSizeChange={handlePageSizeChange}
   246→        itemLabel="Salões"
   247→        pageSizeOptions={DEFAULT_PAGE_SIZE_OPTIONS}
   248→      />
   249→    </EasySalonLayout>
   250→  );
   251→}
