     1→import { httpClient } from './httpClient';
     2→import {
     3→  Salon,
     4→  CreateSalonDto,
     5→  UpdateSalonDto,
     6→  SalonListParams,
     7→  PaginatedSalons,
     8→  SalonSettings,
     9→  OpeningHours,
    10→  OnlineBookingHours,
    11→} from '@/types/salon';
    12→import { API_CONFIG } from '@/config/api';
    13→
    14→class SalonService {
    15→  private readonly basePath = '/salons';
    16→
    17→  async list(params?: SalonListParams): Promise<PaginatedSalons> {
    18→    const queryParams = new URLSearchParams();
    19→    
    20→    if (params?.page) queryParams.append('page', params.page.toString());
    21→    if (params?.limit) queryParams.append('limit', params.limit.toString());
    22→    if (params?.sortBy) queryParams.append('sortBy', params.sortBy);
    23→    if (params?.sortOrder) queryParams.append('sortOrder', params.sortOrder);
    24→    if (params?.search) queryParams.append('search', params.search);
    25→    if (params?.status) {
    26→      queryParams.append('active', params.status === 'active' ? 'true' : 'false');
    27→    }
    28→
    29→    const response = await httpClient.get<PaginatedSalons | Salon[]>(
    30→      `${this.basePath}${queryParams.toString() ? `?${queryParams.toString()}` : ''}`
    31→    );
    32→    
    33→    // Check if response is an array (backend returning array directly)
    34→    if (Array.isArray(response.data)) {
    35→      // Convert array to paginated format
    36→      const page = params?.page || 1;
    37→      const limit = params?.limit || 10;
    38→      return {
    39→        data: response.data,
    40→        total: response.data.length,
    41→        page,
    42→        limit,
    43→        totalPages: Math.ceil(response.data.length / limit)
    44→      };
    45→    }
    46→    
    47→    return response.data;
    48→  }
    49→
    50→  async getById(id: string): Promise<Salon> {
    51→    const response = await httpClient.get<Salon>(`${this.basePath}/${id}`);
    52→    return response.data;
    53→  }
    54→
    55→  async getBySlug(slug: string): Promise<Salon> {
    56→    const response = await httpClient.get<Salon>(`${this.basePath}/slug/${slug}`);
    57→    return response.data;
    58→  }
    59→
    60→  async create(data: CreateSalonDto): Promise<Salon> {
    61→    const response = await httpClient.post<Salon>(this.basePath, data);
    62→    return response.data;
    63→  }
    64→
    65→  async createWithNetwork(data: CreateSalonDto): Promise<{ salon: Salon; network: any }> {
    66→    const response = await httpClient.post<{ salon: Salon; network: any }>(
    67→      `${this.basePath}/with-network`, 
    68→      data
    69→    );
    70→    return response.data;
    71→  }
    72→
    73→  async update(id: string, data: UpdateSalonDto): Promise<Salon> {
    74→    const response = await httpClient.put<Salon>(`${this.basePath}/${id}`, data);
    75→    return response.data;
    76→  }
    77→
    78→  async delete(id: string): Promise<void> {
    79→    await httpClient.delete(`${this.basePath}/${id}`);
    80→  }
    81→
    82→  async deleteSalon(id: string): Promise<void> {
    83→    await httpClient.delete(`${this.basePath}/${id}`);
    84→  }
    85→
    86→  async activate(id: string): Promise<Salon> {
    87→    const response = await httpClient.put<Salon>(`${this.basePath}/${id}/activate`);
    88→    return response.data;
    89→  }
    90→
    91→  async deactivate(id: string): Promise<Salon> {
    92→    const response = await httpClient.put<Salon>(`${this.basePath}/${id}/deactivate`);
    93→    return response.data;
    94→  }
    95→
    96→  async uploadLogo(id: string, file: File): Promise<{ logoUrl: string }> {
    97→    const formData = new FormData();
    98→    formData.append('file', file);
    99→
   100→    httpClient.setTimeoutForUploads();
   101→    
   102→    try {
   103→      const response = await httpClient.post<{ logoUrl: string }>(
   104→        `${this.basePath}/${id}/logo`,
   105→        formData,
   106→        {
   107→          headers: {
   108→            'Content-Type': 'multipart/form-data',
   109→          },
   110→        }
   111→      );
   112→      
   113→      return response.data;
   114→    } finally {
   115→      httpClient.resetTimeout();
   116→    }
   117→  }
   118→
   119→  async uploadImage(id: string, file: File): Promise<{ imageUrl: string }> {
   120→    const formData = new FormData();
   121→    formData.append('image', file);
   122→
   123→    httpClient.setTimeoutForUploads();
   124→    
   125→    try {
   126→      const response = await httpClient.post<{ imageUrl: string }>(
   127→        `${this.basePath}/${id}/images`,
   128→        formData,
   129→        {
   130→          headers: {
   131→            'Content-Type': 'multipart/form-data',
   132→          },
   133→        }
   134→      );
   135→      
   136→      return response.data;
   137→    } finally {
   138→      httpClient.resetTimeout();
   139→    }
   140→  }
   141→
   142→  async deleteImage(id: string, imageUrl: string): Promise<void> {
   143→    await httpClient.delete(`${this.basePath}/${id}/images`, {
   144→      data: { imageUrl }
   145→    });
   146→  }
   147→
   148→  async getDefaultSettings(): Promise<SalonSettings> {
   149→    return {
   150→      allowOnlineBooking: true,
   151→      requireConfirmation: false,
   152→      cancellationMinHours: 24,
   153→      maxAdvanceBookingDays: 30,
   154→      minAdvanceBookingHours: 2,
   155→      blockScheduleAfterBooking: true,
   156→      defaultServiceDuration: 60,
   157→      slotInterval: 15
   158→    };
   159→  }
   160→
   161→  async getDefaultOpeningHours(): Promise<OpeningHours[]> {
   162→    const days = ['Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado', 'Domingo'];
   163→    
   164→    return days.map((_, index) => ({
   165→      dayOfWeek: index === 6 ? 0 : index + 1,
   166→      open: index === 6 ? '09:00' : '08:00',
   167→      close: index === 6 ? '13:00' : index === 5 ? '17:00' : '18:00',
   168→      isOpen: index !== 6
   169→    }));
   170→  }
   171→
   172→  async getWorkingHours(id: string): Promise<OpeningHours[]> {
   173→    const salon = await this.getById(id);
   174→    return salon.openingHours || await this.getDefaultOpeningHours();
   175→  }
   176→
   177→  async updateWorkingHours(id: string, workingHours: OpeningHours[]): Promise<Salon> {
   178→    const response = await httpClient.put<Salon>(
   179→      `${this.basePath}/${id}/working-hours`,
   180→      workingHours
   181→    );
   182→    return response.data;
   183→  }
   184→
   185→  async getBookingSettings(id: string): Promise<SalonSettings> {
   186→    const salon = await this.getById(id);
   187→    return salon.settings || await this.getDefaultSettings();
   188→  }
   189→
   190→  async updateBookingSettings(id: string, settings: Partial<SalonSettings>): Promise<Salon> {
   191→    const response = await httpClient.put<Salon>(
   192→      `${this.basePath}/${id}/settings`,
   193→      settings
   194→    );
   195→
   196→    return response.data;
   197→  }
   198→
   199→  validateCNPJ(cnpj: string): boolean {
   200→    cnpj = cnpj.replace(/[^\d]+/g, '');
   201→
   202→    if (cnpj.length !== 14) return false;
   203→    
   204→    if (/^(\d)\1{13}$/.test(cnpj)) return false;
   205→
   206→    let tamanho = cnpj.length - 2;
   207→    let numeros = cnpj.substring(0, tamanho);
   208→    const digitos = cnpj.substring(tamanho);
   209→    let soma = 0;
   210→    let pos = tamanho - 7;
   211→    
   212→    for (let i = tamanho; i >= 1; i--) {
   213→      soma += parseInt(numeros.charAt(tamanho - i)) * pos--;
   214→      if (pos < 2) pos = 9;
   215→    }
   216→    
   217→    let resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
   218→    if (resultado !== parseInt(digitos.charAt(0))) return false;
   219→
   220→    tamanho = tamanho + 1;
   221→    numeros = cnpj.substring(0, tamanho);
   222→    soma = 0;
   223→    pos = tamanho - 7;
   224→    
   225→    for (let i = tamanho; i >= 1; i--) {
   226→      soma += parseInt(numeros.charAt(tamanho - i)) * pos--;
   227→      if (pos < 2) pos = 9;
   228→    }
   229→    
   230→    resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
   231→    if (resultado !== parseInt(digitos.charAt(1))) return false;
   232→
   233→    return true;
   234→  }
